const intent = $json.intent || '';
const params = $json.intentParams || {};
const accessToken = $json.accessToken || '';
if (!accessToken) { return [{ json: { ...$json, responseText: '⚠️ Google Auth failed: no access token.', success: false } }]; }
let endpoint, queryParams, method = 'GET', body = null;
if (intent === 'drive_list') {
  endpoint = 'https://www.googleapis.com/drive/v3/files';
  queryParams = { pageSize: Math.min(params.page_size || 10, 100), fields: 'files(id,name,mimeType,modifiedTime,size)', orderBy: 'modifiedTime desc' };
  if (params.q) queryParams.q = params.q;
} else if (intent === 'drive_search') {
  endpoint = 'https://www.googleapis.com/drive/v3/files';
  queryParams = { pageSize: Math.min(params.max_results || 10, 100), q: `name contains '${params.query || params.q || ''}'`, fields: 'files(id,name,mimeType,modifiedTime)' };
} else if (intent === 'drive_upload') {
  const { name, content_base64, mime_type, parents } = params;
  if (!name || !content_base64) return [{ json: { ...$json, responseText: '❗ name and content_base64 required.', success: false } }];
  endpoint = 'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart';
  method = 'POST';
  const metadata = { name };
  if (mime_type) metadata.mimeType = mime_type;
  if (parents) metadata.parents = parents;
  body = { metadata, media: { mimeType: mime_type || 'application/octet-stream', body: content_base64 } };
} else if (intent === 'drive_download') {
  const fileId = params.file_id || params.id;
  if (!fileId) return [{ json: { ...$json, responseText: '❗ File ID required.', success: false } }];
  endpoint = `https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`;
} else if (intent === 'drive_delete') {
  const fileId = params.file_id || params.id;
  if (!fileId) return [{ json: { ...$json, responseText: '❗ File ID required.', success: false } }];
  endpoint = `https://www.googleapis.com/drive/v3/files/${fileId}`;
  method = 'DELETE';
} else { return [{ json: { ...$json, responseText: '❓ Unknown Drive intent: ' + intent, success: false } }]; }
return [{ json: { ...$json, apiEndpoint: endpoint, apiParams: queryParams, apiMethod: method, apiBody: body, bearerToken: accessToken, _ctx: { intent, params, accessToken, source: $json.source, userId: $json.userId, sessionId: $json.sessionId, inputText: $json.inputText } } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const files = $json.files || [];
if ($json.id && !$json.files) {
  if ($json.name) return [{ json: { ...ctx, responseText: `📁 Uploaded: ${$json.name} (ID: ${$json.id})`, success: true, intent: ctx.intent } }];
  if ($json.size) return [{ json: { ...ctx, responseText: `📁 Downloaded file (${$json.size} bytes)`, success: true, intent: ctx.intent } }];
  return [{ json: { ...ctx, responseText: '✅ Drive operation completed.', success: true, intent: ctx.intent } }];
}
if (files.length === 0) { return [{ json: { ...ctx, responseText: '📁 No files found in Drive.', success: true, intent: ctx.intent } }]; }
let text = '📁 Google Drive Files:

';
files.forEach((f, i) => {
  const icon = f.mimeType === 'application/vnd.google-apps.folder' ? '📂' : '📄';
  const size = f.size ? `(${(f.size / 1024).toFixed(1)} KB)` : '';
  text += `${icon} <b>${f.name}</b> ${size}\n`;
});
text += `\n📁 ${files.length} file(s) found`;
return [{ json: { ...ctx, responseText: text, success: true, intent: ctx.intent } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) { console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](JSON.stringify({ timestamp: new Date().toISOString(), level, traceId: ctx.sessionId || 'unknown', workflow: 'drive-agent', message, meta })); }
};
const statusCode = $json.statusCode || $json.error?.statusCode || 0;
const statusMessage = $json.statusMessage || $json.error?.message || 'Unknown error';
if (statusCode === 401) {
  jarvisLog('warn', 'Token expired, attempting refresh', { intent: ctx.intent });
  try {
    const authRes = await $helpers.httpRequest({ method: 'POST', url: 'https://oauth2.googleapis.com/token', headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body: 'client_id=' + encodeURIComponent($env.GOOGLE_CLIENT_ID) + '&client_secret=' + encodeURIComponent($env.GOOGLE_CLIENT_SECRET) + '&refresh_token=' + encodeURIComponent($env.GOOGLE_REFRESH_TOKEN) + '&grant_type=refresh_token', timeout: 15000 });
    const retryRes = await $helpers.httpRequest({ method: $('Build Request').first().json.apiMethod || 'GET', url: $('Build Request').first().json.apiEndpoint, headers: { 'Authorization': 'Bearer ' + authRes.access_token }, body: $('Build Request').first().json.apiBody, timeout: 30000 });
    return [{ json: { ...retryRes, _ctx: ctx } }];
  } catch (retryErr) {
    jarvisLog('error', 'Auth retry failed', { intent: ctx.intent, error: retryErr.message });
    return [{ json: { ...ctx, responseText: '⚠️ Authentication failed after refresh. Please re-authenticate Google OAuth.', success: false, intent: ctx.intent } }];
  }
}
jarvisLog('error', 'API request failed', { intent: ctx.intent, statusCode, statusMessage });
return [{ json: { ...ctx, responseText: '⚠️ Could not complete your request. API returned error ' + statusCode + ': ' + statusMessage + '. Please try again.', success: false, intent: ctx.intent, error: { statusCode, provider: 'drive', intent: ctx.intent } } }];
